import java.text.NumberFormat; import java.util.Locale; public class prog_002_variables { public static void main(String[] args){ String message; int year; double prijs; message = &#34;De beste wensen voor: &#34;; year = 2025; prijs = 2.50; // Combine the creation of the Locale and the NumberFormat in one line NumberFormat currencyFormat; currencyFormat = NumberFormat.getCurrencyInstance(new Locale(&#34;nl&#34;, &#34;NL&#34;)); System.out.println(message + year + &#34;, een frikandel kost nu: &#34; + currencyFormat.format(prijs)); currencyFormat = NumberFormat.getCurrencyInstance(new Locale(&#34;de&#34;, &#34;CH&#34;)); System.out.println(message + year + &#34;, een frikandel kost nu: &#34; + currencyFormat.format(prijs)); } }
